const webhook = $('Receber pergunta do Sistema').first().json || {};
const body = webhook.body || webhook || {};
const data = $json || {};

const pergunta = String(body.message || body.pergunta || body.question || '').trim();
if (!pergunta) {
  return [{ json: { ok: false, error: 'Pergunta vazia.' } }];
}

function cleanObject(obj = {}) {
  const out = {};
  for (const [key, value] of Object.entries(obj || {})) {
    if (value === undefined || value === null || value === '') continue;
    if (/logo|base64|imagem|image|file|arquivo|anexo/i.test(key)) continue;
    if (typeof value === 'object') continue;
    out[key] = value;
  }
  return out;
}

const clientes = (data.clientes || data.data?.clientes || []).map(c => cleanObject(c));
const colaboradores = (data.colaboradores || data.data?.colaboradores || []).map(c => cleanObject(c));
const publicacoes = (data.publicacoes || data.data?.publicacoes || []).map(p => cleanObject(p));
const eventos = (data.eventos || data.data?.eventos || []).map(e => cleanObject(e));
const financeBoxes = (data.finance_boxes || data.caixinhas || data.data?.finance_boxes || []).map(b => cleanObject(b));
const financeMovements = (data.finance_movements || data.movimentacoes || data.data?.finance_movements || []).map(m => cleanObject(m));
const prospects = (data.crm_prospects || data.data?.crm_prospects || []).map(p => cleanObject(p));
const acoesCrm = (data.crm_acoes || data.data?.crm_acoes || []).map(a => cleanObject(a));

const contexto = {
  atualizado_em: new Date().toISOString(),
  usuario: body.user || {},
  historico_recente: Array.isArray(body.history) ? body.history.slice(-8).map(h => ({ role: h.role, content: h.content })) : [],
  clientes,
  colaboradores,
  publicacoes,
  eventos,
  financeiro: {
    caixinhas: financeBoxes,
    movimentacoes: financeMovements
  },
  crm: {
    prospects,
    acoes: acoesCrm
  }
};

return [{
  json: {
    ok: true,
    pergunta,
    contexto_json: JSON.stringify(contexto, null, 2)
  }
}];

